"""Self-contained judge UI for the verified remediation workflow.

The interface deliberately consumes the same API contracts as an external
frontend would: scenarios and capabilities are loaded from the backend rather
than duplicated in JavaScript.
"""

HTML = r'''<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
  <title>AutoSolve AI | Verified Remediation</title>
  <style>
    :root{--bg:#f4f7fb;--surface:#fff;--ink:#172033;--muted:#69758a;--line:#dfe6f0;--blue:#2563eb;--blue-soft:#eff6ff;--green:#059669;--green-soft:#ecfdf5;--amber:#b45309;--amber-soft:#fffbeb;--red:#dc2626;--red-soft:#fef2f2;--shadow:0 10px 30px rgba(23,32,51,.07);--radius:14px}
    *{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--ink);font:14px/1.5 Inter,ui-sans-serif,system-ui,-apple-system,"Segoe UI",sans-serif}button,select{font:inherit}button{cursor:pointer}.shell{min-height:100vh}.topbar{height:64px;background:var(--surface);border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between;padding:0 clamp(18px,4vw,56px);position:relative;z-index:3}.brand{display:flex;align-items:center;gap:11px;font-weight:750;letter-spacing:-.02em}.mark{height:31px;width:31px;display:grid;place-items:center;border-radius:9px;background:linear-gradient(135deg,#2563eb,#7c3aed);color:#fff;font-weight:800}.brand small{display:block;color:var(--muted);font-size:11px;font-weight:500;letter-spacing:0}.top-meta{display:flex;align-items:center;gap:14px;color:var(--muted);font-size:12px}.dot{height:8px;width:8px;border-radius:50%;background:var(--green);box-shadow:0 0 0 4px var(--green-soft)}.page{max-width:1440px;margin:0 auto;padding:34px clamp(18px,4vw,56px) 72px}.hero{display:flex;justify-content:space-between;align-items:flex-end;gap:20px;margin-bottom:25px}.eyebrow{color:var(--blue);font-size:11px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;margin:0 0 8px}.hero h1{font-size:32px;letter-spacing:-.04em;line-height:1.15;margin:0 0 8px}.hero p{color:var(--muted);margin:0;max-width:660px}.hero-actions{display:flex;gap:9px;flex-wrap:wrap}.button{border:1px solid transparent;border-radius:9px;padding:10px 14px;font-weight:700;transition:.16s ease;display:inline-flex;align-items:center;gap:8px}.button:disabled{opacity:.45;cursor:not-allowed}.button.primary{background:var(--blue);color:#fff;box-shadow:0 5px 14px rgba(37,99,235,.18)}.button.primary:hover:not(:disabled){background:#1d4ed8;transform:translateY(-1px)}.button.secondary{background:var(--surface);border-color:var(--line);color:var(--ink)}.button.secondary:hover:not(:disabled){border-color:#b8c6da;background:#f8fafc}.button.success{background:var(--green);color:#fff}.button.danger{background:var(--red);color:#fff}.layout{display:grid;grid-template-columns:minmax(260px,350px) minmax(0,1fr);gap:20px;align-items:start}.stack{display:grid;gap:16px}.card{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);box-shadow:var(--shadow);padding:20px}.card-head{display:flex;justify-content:space-between;align-items:flex-start;gap:12px;margin-bottom:16px}.card h2,.card h3{margin:0;font-size:15px;letter-spacing:-.01em}.card-sub{color:var(--muted);font-size:12px;margin:4px 0 0}.label{font-size:11px;color:var(--muted);font-weight:750;letter-spacing:.05em;text-transform:uppercase;display:block;margin:0 0 7px}.select{width:100%;border:1px solid var(--line);border-radius:8px;background:#fff;padding:10px 11px;color:var(--ink);outline:none}.select:focus{border-color:#93b4f8;box-shadow:0 0 0 3px var(--blue-soft)}.field{margin-bottom:15px}.mode-row{display:grid;grid-template-columns:1fr 1fr;gap:8px}.mode{border:1px solid var(--line);border-radius:9px;background:#fff;padding:11px;text-align:left;color:var(--muted)}.mode strong{display:block;color:var(--ink);font-size:12px}.mode.active{border-color:#93b4f8;background:var(--blue-soft);color:#315da8}.scenario-list{display:grid;gap:8px}.scenario{border:1px solid var(--line);border-radius:10px;background:#fff;text-align:left;padding:12px;transition:.15s}.scenario:hover{border-color:#9eb8e8}.scenario.active{border-color:var(--blue);box-shadow:0 0 0 3px var(--blue-soft)}.scenario-title{font-weight:750}.scenario-desc{color:var(--muted);font-size:12px;margin-top:3px}.status-pill{border-radius:999px;padding:4px 9px;font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;white-space:nowrap}.status-pill.idle,.status-pill.alerted{background:#f1f5f9;color:#475569}.status-pill.planned,.status-pill.approved{background:var(--blue-soft);color:#1d4ed8}.status-pill.executing{background:var(--amber-soft);color:var(--amber)}.status-pill.verified,.status-pill.shadowed{background:var(--green-soft);color:var(--green)}.status-pill.failed{background:var(--red-soft);color:var(--red)}.steps{display:grid;grid-template-columns:repeat(5,1fr);gap:6px;margin-bottom:20px}.step{position:relative;text-align:center;color:#9aa6b8;font-size:10px;font-weight:750}.step:before{content:"";display:block;height:7px;border-radius:99px;background:#e7edf5;margin-bottom:7px}.step.done{color:var(--green)}.step.done:before{background:#34d399}.step.current{color:var(--blue)}.step.current:before{background:#60a5fa}.metric-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px}.metric{border:1px solid var(--line);border-radius:10px;padding:13px;background:#fbfcfe}.metric-label{font-size:11px;color:var(--muted);display:block;margin-bottom:3px}.metric-value{font-weight:800;font-size:18px;letter-spacing:-.03em;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.metric-value.good{color:var(--green)}.metric-value.bad{color:var(--red)}.metric-value.warn{color:var(--amber)}.grid-two{display:grid;grid-template-columns:1fr 1fr;gap:16px}.plan-box{background:#f8fafc;border:1px solid var(--line);border-radius:10px;padding:14px}.plan-row{display:flex;justify-content:space-between;gap:16px;border-bottom:1px solid var(--line);padding:9px 0}.plan-row:first-child{padding-top:0}.plan-row:last-child{border-bottom:0;padding-bottom:0}.plan-key{color:var(--muted);font-size:12px}.plan-value{text-align:right;font-weight:700;max-width:65%;overflow-wrap:anywhere}.reasoning{margin:13px 0 0;color:#46536a;font-size:13px}.chips{display:flex;gap:6px;flex-wrap:wrap;margin-top:12px}.chip{background:#eef2ff;color:#4338ca;border-radius:999px;padding:4px 8px;font-size:11px;font-weight:700}.evidence{display:grid;grid-template-columns:1fr 1fr;gap:10px}.evidence-pane{border:1px solid var(--line);border-radius:10px;padding:13px}.evidence-pane.after{border-color:#a7f3d0;background:var(--green-soft)}.evidence-pane h4{margin:0 0 8px;font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.07em}.evidence-line{display:flex;justify-content:space-between;gap:12px;font-size:12px;padding:4px 0}.evidence-line span:last-child{font-weight:700;text-align:right}.timeline{display:grid;gap:0}.event{display:grid;grid-template-columns:18px 1fr auto;gap:10px;align-items:start;padding:10px 0;border-bottom:1px solid var(--line)}.event:last-child{border:0}.event-dot{height:9px;width:9px;border-radius:50%;background:#93c5fd;margin-top:5px;box-shadow:0 0 0 4px #eff6ff}.event-name{font-weight:750;font-size:12px}.event-time,.event-hash{font-size:11px;color:var(--muted)}.empty{color:var(--muted);text-align:center;padding:25px 10px;border:1px dashed var(--line);border-radius:10px}.toast{position:fixed;right:22px;bottom:22px;background:#172033;color:#fff;border-radius:10px;padding:13px 16px;box-shadow:var(--shadow);max-width:380px;z-index:5}.toast.error{background:#991b1b}.muted{color:var(--muted)}.mono{font-family:ui-monospace,SFMono-Regular,Consolas,monospace;font-size:11px}.hidden{display:none!important}@media(max-width:980px){.layout{grid-template-columns:1fr}.hero{align-items:flex-start;flex-direction:column}.grid-two{grid-template-columns:1fr}}@media(max-width:620px){.page{padding:24px 14px 50px}.topbar{padding:0 14px}.top-meta span{display:none}.hero h1{font-size:26px}.metric-grid{grid-template-columns:1fr 1fr}.evidence{grid-template-columns:1fr}.steps{gap:3px}.step{font-size:9px}}
  </style>
</head>
<body>
  <div class="shell">
    <header class="topbar"><div class="brand"><div class="mark">A</div><div>AutoSolve AI<small>Verified remediation sandbox</small></div></div><div class="top-meta"><span class="dot"></span><span>Local synthetic environment</span><span class="mono" id="headerRun">No active run</span></div></header>
    <main class="page">
      <section class="hero"><div><p class="eyebrow">Incident command center</p><h1>Turn an alert into verified proof.</h1><p>Inspect the target, generate a constrained AI plan, enforce policy, execute one allowlisted action, and show the evidence that it worked.</p></div><div class="hero-actions"><button class="button secondary" id="refreshBtn">Refresh state</button><button class="button primary" id="startBtn">Simulate alert</button></div></section>
      <div class="layout">
        <aside class="stack">
          <section class="card"><div class="card-head"><div><h2>Run a scenario</h2><p class="card-sub">Synthetic faults only. Nothing touches a real host.</p></div></div><div class="field"><label class="label" for="mode">Execution policy</label><div class="mode-row"><button class="mode active" data-mode="approval"><strong>Approval</strong>Human gate</button><button class="mode" data-mode="shadow"><strong>Shadow</strong>No mutation</button></div></div><div class="field"><label class="label" for="customTitle">Try any incident</label><input class="select" id="customTitle" placeholder="Snipping Tool won't close"><textarea class="select" id="customMessage" rows="3" placeholder="Describe what is happening..."></textarea><p class="card-sub">Leave blank for a synthetic scenario. Custom text creates a fresh incident and a dynamic plan.</p></div><label class="label">Incident type</label><div class="scenario-list" id="scenarioList"><div class="empty">Loading scenarios...</div></div></section>
          <section class="card"><div class="card-head"><div><h2>Available capabilities</h2><p class="card-sub">Loaded from the backend registry.</p></div><span class="status-pill idle" id="capabilityCount">—</span></div><div class="chips" id="capabilityList"><span class="muted">Loading...</span></div></section>
          <section class="card"><div class="card-head"><div><h2>Connector fabric</h2><p class="card-sub">Provider-shaped adapters, simulator scoped.</p></div><span class="status-pill idle" id="connectorStatus">—</span></div><div class="timeline" id="connectorList"><div class="empty">Loading connector health...</div></div></section>
        </aside>
        <section class="stack">
          <section class="card"><div class="card-head"><div><h2 id="runTitle">No active incident</h2><p class="card-sub" id="runSubtitle">Choose a scenario to begin the controlled workflow.</p></div><span class="status-pill idle" id="runStatus">Idle</span></div><div class="steps" id="steps"><div class="step">Alert</div><div class="step">Inspect</div><div class="step">Plan</div><div class="step">Execute</div><div class="step">Verify</div></div><div class="metric-grid"><div class="metric"><span class="metric-label">Target</span><span class="metric-value" id="mTarget">—</span></div><div class="metric"><span class="metric-label">Process</span><span class="metric-value" id="mProcess">—</span></div><div class="metric"><span class="metric-label">Heartbeat</span><span class="metric-value" id="mHeartbeat">—</span></div><div class="metric"><span class="metric-label">Outcome</span><span class="metric-value" id="mOutcome">—</span></div></div></section>
          <section class="grid-two"><section class="card"><div class="card-head"><div><h2>AI remediation plan</h2><p class="card-sub">Structured, signed, and checked against the registry.</p></div><span class="status-pill idle" id="planSource">Waiting</span></div><div id="planPanel" class="empty">Generate a plan after the alert is inspected.</div></section><section class="card"><div class="card-head"><div><h2>Operator action</h2><p class="card-sub">Every mutation is gated and independently verified.</p></div></div><div id="actionPanel" class="empty">Start a scenario to see the next safe action.</div></section></section>
          <section class="card"><div class="card-head"><div><h2>Evidence comparison</h2><p class="card-sub">Before and after snapshots from the disposable worker.</p></div><span class="status-pill idle" id="evidenceStatus">Not run</span></div><div id="evidencePanel" class="empty">Execution evidence will appear here.</div></section>
          <section class="card"><div class="card-head"><div><h2>Audit trail</h2><p class="card-sub">Append-only events with hash-chain verification.</p></div><button class="button secondary" id="verifyBtn">Verify chain</button></div><div id="timeline" class="timeline"><div class="empty">No events yet.</div></div></section>
        </section>
      </div>
    </main>
    <div id="toast" class="toast hidden"></div>
  </div>
  <script>
    const state={run:null,scenarios:[],capabilities:[],mode:'approval',busy:false};
    const $=id=>document.getElementById(id);
    const esc=value=>String(value??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
    const call=async(path,method='GET',body)=>{const response=await fetch(path,{method,headers:{'content-type':'application/json'},body:body?JSON.stringify(body):undefined});let payload={};try{payload=await response.json()}catch{}if(!response.ok)throw Error(payload.error||`Request failed (${response.status})`);return payload};
    const notify=(message,error=false)=>{const node=$('toast');node.textContent=message;node.className=`toast${error?' error':''}`;clearTimeout(window.toastTimer);window.toastTimer=setTimeout(()=>node.className='toast hidden',5000)};
    const statusClass=value=>String(value||'idle').toLowerCase().replace(/[^a-z]/g,'');
    const fmtTime=value=>value?new Date(Number(value)*1000).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit',second:'2-digit'}):'—';
    function selectedScenario(){return document.querySelector('.scenario.active')?.dataset.name||state.scenarios[0]?.name||'stale_heartbeat'}
    function renderScenarios(){
      $('scenarioList').innerHTML=state.scenarios.length?state.scenarios.map((item,index)=>`<button class="scenario${index===0?' active':''}" data-name="${esc(item.name)}"><div class="scenario-title">${esc(item.alert_title||item.name)}</div><div class="scenario-desc">${esc(item.description||'Synthetic incident')}</div></button>`).join(''):'<div class="empty">No scenarios registered.</div>';
      document.querySelectorAll('.scenario').forEach(node=>node.onclick=()=>{document.querySelectorAll('.scenario').forEach(other=>other.classList.remove('active'));node.classList.add('active')});
    }
    function renderCapabilities(){ $('capabilityCount').textContent=`${state.capabilities.length} loaded`; $('capabilityList').innerHTML=state.capabilities.map(item=>`<span class="chip">${esc(item.name||item)}</span>`).join('')||'<span class="muted">No capabilities registered.</span>' }
    function renderConnectors(payload){const adapters=payload?.adapters||{};$('connectorStatus').textContent=payload?.healthy?'All ready':'Attention';$('connectorStatus').className=`status-pill ${payload?.healthy?'verified':'failed'}`;$('connectorList').innerHTML=Object.entries(adapters).map(([name,item])=>`<div class="event"><span class="event-dot"></span><div><div class="event-name">${esc(name)}</div><div class="event-time">${esc(item?.data?.provider||item?.status||'registered')}</div></div><span class="event-hash">${item?.ok?'ready':'check'}</span></div>`).join('')||'<div class="empty">No connectors registered.</div>'}
    function stageIndex(run){const status=String(run?.status||'').toLowerCase();if(!run)return 0;if(status==='alerted')return 1;if(status==='planned'||status==='approved')return 2;if(status==='executing')return 3;if(['verified','failed','shadowed'].includes(status))return 4;return 0}
    function renderSteps(){const index=stageIndex(state.run);document.querySelectorAll('.step').forEach((node,i)=>{node.classList.toggle('done',i<index);node.classList.toggle('current',i===index)})}
    function renderPlan(run){const plan=run?.plan;if(!plan){$('planSource').textContent='Waiting';$('planSource').className='status-pill idle';$('planPanel').className='empty';$('planPanel').textContent='Generate a plan after the alert is inspected.';return}$('planSource').textContent=plan.source||'validated';$('planSource').className=`status-pill ${plan.source==='openai'?'planned':'approved'}`;$('planPanel').className='plan-box';$('planPanel').innerHTML=`<div class="plan-row"><span class="plan-key">Capability</span><span class="plan-value mono">${esc(plan.capability)}</span></div><div class="plan-row"><span class="plan-key">Target</span><span class="plan-value mono">${esc(plan.target)}</span></div><div class="plan-row"><span class="plan-key">Risk</span><span class="plan-value">${esc(plan.risk||'sandbox_only')}</span></div><p class="reasoning">${esc(plan.reasoning||'No reasoning supplied.')}</p><div class="chips">${(plan.steps||[]).map(step=>`<span class="chip">${esc(step)}</span>`).join('')}</div>${run.route_preview?.explanation?`<p class="card-sub">Router: ${esc(run.route_preview.explanation)}</p>`:''}${run.runbook?.steps?.length?`<p class="card-sub">Generated runbook: ${run.runbook.steps.length} dependency-ordered steps</p>`:''}`}
    function renderEvidence(run){const before=run?.inspection||{};const after=run?.verification||run?.result?.verification;if(!after){$('evidencePanel').className='empty';$('evidencePanel').textContent='Execution evidence will appear here.';$('evidenceStatus').textContent='Not run';$('evidenceStatus').className='status-pill idle';return}const healthy=Boolean(after.healthy);$('evidenceStatus').textContent=healthy?'Verified':'Failed';$('evidenceStatus').className=`status-pill ${healthy?'verified':'failed'}`;const pane=(label,item,afterPane)=>`<div class="evidence-pane${afterPane?' after':''}"><h4>${label}</h4><div class="evidence-line"><span>Process</span><span>${item.alive?'alive':'stopped'}</span></div><div class="evidence-line"><span>Health</span><span>${item.healthy?'healthy':'unhealthy'}</span></div><div class="evidence-line"><span>PID</span><span class="mono">${esc(item.pid||'—')}</span></div><div class="evidence-line"><span>Heartbeat</span><span>${esc(item.heartbeat_age_seconds==null?'—':`${Number(item.heartbeat_age_seconds).toFixed(2)}s`)}</span></div></div>`;$('evidencePanel').className='evidence';$('evidencePanel').innerHTML=pane('Before',before,false)+pane('After',after,true)}
    function renderAction(run){const status=String(run?.status||'').toLowerCase();let html='';if(!run)html='<div class="empty">Start a scenario to see the next safe action.</div>';else if(status==='alerted')html='<button class="button primary" data-action="plan">Generate constrained AI plan</button><p class="card-sub">The inspected target and capability manifest are sent to the planner.</p>';else if(status==='planned'&&state.mode==='approval')html='<button class="button primary" data-action="approve">Approve plan</button><p class="card-sub">Execution remains blocked until this explicit approval.</p>';else if((status==='planned'&&state.mode==='shadow')||status==='approved')html='<button class="button success" data-action="execute">Execute and verify</button><p class="card-sub">Runs the allowlisted action and checks the target independently.</p>';else if(status==='verified')html='<div><span class="status-pill verified">Verified ✓</span><p class="card-sub">The worker is healthy and the audit evidence is complete.</p><button class="button secondary" data-action="rollback">Reset sandbox</button></div>';else if(status==='shadowed')html='<div><span class="status-pill approved">Shadow complete</span><p class="card-sub">No target mutation was performed.</p><button class="button secondary" data-action="rollback">Reset sandbox</button></div>';else if(status==='failed')html='<div><span class="status-pill failed">Verification failed</span><p class="card-sub">The result is not considered resolved.</p><button class="button secondary" data-action="rollback">Rollback to healthy</button></div>';else html='<span class="muted">Working…</span>';$('actionPanel').className='';$('actionPanel').innerHTML=html;$('actionPanel').querySelector('[data-action]')?.addEventListener('click',()=>runAction($('actionPanel').querySelector('[data-action]').dataset.action))}
    function renderTimeline(events){if(!events.length){$('timeline').innerHTML='<div class="empty">No events yet.</div>';return}$('timeline').innerHTML=events.map(event=>`<div class="event"><span class="event-dot"></span><div><div class="event-name">${esc(event.event||'event')}</div><div class="event-time">${fmtTime(event.timestamp)}</div></div><span class="event-hash mono">${esc(String(event.hash||'').slice(0,10))}…</span></div>`).join('')}
    function render(){const run=state.run;const inspection=run?.verification||run?.inspection||{};const status=run?.status||'idle';$('headerRun').textContent=run?`Run ${String(run.run_id).slice(0,8)}`:'No active run';$('runTitle').textContent=run?.alert?.title||'No active incident';$('runSubtitle').textContent=run?.alert?.message||'Choose a scenario to begin the controlled workflow.';$('runStatus').textContent=status;$('runStatus').className=`status-pill ${statusClass(status)}`;$('mTarget').textContent=inspection.target||'—';$('mProcess').textContent=inspection.alive==null?'—':inspection.alive?`PID ${inspection.pid}`:'stopped';$('mProcess').className=`metric-value ${inspection.alive?'':'bad'}`;$('mHeartbeat').textContent=inspection.heartbeat_age_seconds==null?'—':`${Number(inspection.heartbeat_age_seconds).toFixed(1)}s`;$('mHeartbeat').className=`metric-value ${inspection.healthy?'good':'warn'}`;$('mOutcome').textContent=status==='verified'?'VERIFIED':status==='shadowed'?'SHADOW ONLY':'—';$('mOutcome').className=`metric-value ${['verified','shadowed'].includes(status)?'good':''}`;renderSteps();renderPlan(run);renderEvidence(run);renderAction(run)}
    async function load(){try{const [scenarios,capabilities,serverState,connectors]=await Promise.all([call('/api/scenarios'),call('/api/capabilities'),call('/api/state'),call('/api/connectors')]);state.scenarios=Object.entries(scenarios).map(([name,item])=>({name,...item}));state.capabilities=Object.entries(capabilities).map(([name,item])=>({name,...item}));state.run=serverState.runs?.at(-1)||null;renderScenarios();renderCapabilities();renderConnectors(connectors);render();if(state.run)await loadEvents()}catch(error){notify(error.message,true)}}
    async function loadEvents(){if(!state.run)return;try{renderTimeline(await call(`/api/runs/${state.run.run_id}/replay`))}catch(error){notify(error.message,true)}}
    async function runAction(action){if(state.busy)return;state.busy=true;try{let result;if(action==='alert'){const title=$('customTitle').value.trim();const message=$('customMessage').value.trim();const body={mode:state.mode};if(title||message){body.title=title||'Custom incident';body.message=message||title;body.service='synthetic-app'}else body.scenario=selectedScenario();result=await call('/api/alerts','POST',body)}else if(action==='plan')result=await call(`/api/runs/${state.run.run_id}/plan`,'POST',{});else if(action==='approve')result=await call(`/api/runs/${state.run.run_id}/approve`,'POST',{});else if(action==='execute')result=await call(`/api/runs/${state.run.run_id}/execute`,'POST',{});else if(action==='rollback')result=await call(`/api/runs/${state.run.run_id}/rollback`,'POST',{});if(result)state.run=result;await loadEvents();render();if(['verified','shadowed'].includes(String(state.run?.status).toLowerCase()))notify('Run complete. Evidence and audit trail are available below.')}catch(error){notify(error.message,true)}finally{state.busy=false}}
    const baseRenderEvidence=renderEvidence;renderEvidence=function(run){baseRenderEvidence(run);const terminated=run?.status==='verified'&&run?.plan?.capability==='terminate_sandbox_worker'&&run?.verification?.alive===false;if(terminated){$('evidenceStatus').textContent='Verified';$('evidenceStatus').className='status-pill verified';const after=$('evidencePanel').querySelector('.evidence-pane.after');if(after){const lines=after.querySelectorAll('.evidence-line');if(lines[1])lines[1].querySelector('span:last-child').textContent='not applicable'}const copy=$('actionPanel').querySelector('.card-sub');if(copy)copy.textContent='The process is stopped and the remediation evidence is complete.'}};
    document.querySelectorAll('.mode').forEach(button=>button.addEventListener('click',()=>{document.querySelectorAll('.mode').forEach(other=>other.classList.remove('active'));button.classList.add('active');state.mode=button.dataset.mode}));$('startBtn').onclick=()=>runAction('alert');$('refreshBtn').onclick=load;$('verifyBtn').onclick=async()=>{try{const result=await call('/api/audit/verify');notify(result.valid?`Audit chain valid (${result.events} events).`:`Audit chain failed: ${result.failures?.[0]||'unknown error'}`,!result.valid)}catch(error){notify(error.message,true)}};load();
  </script>
</body></html>'''
